local xml = require "lxp.lxp"

function parse_xml(xml_string)
    local parser, event, tag, attr, txt = xml.parse(xml_string)
    while true do
        event, tag, attr, txt = parser:next()
        if event == "start" then
            print("Start Tag: " .. tag)
        elseif event == "data" then
            print("Text: " .. txt)
        elseif event == "end" then
            print("End Tag: " .. tag)
        elseif event == "error" then
            error(attr)
        end
    end
end

-- Example usage in OpenResty context
local xml_request_body = ngx.req.get_body_data()
if xml_request_body then
    parse_xml(xml_request_body)
else
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("No XML data found in request body")
end